export default function SupportWidget() {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  // Close on outside click
  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    if (open) document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, [open]);

  return (
    <div ref={ref} className="fixed bottom-6 right-6 z-50 flex flex-col items-end gap-3">
      {/* Channel buttons — animate in/out */}
      <div
        className={`flex flex-col items-end gap-2 transition-all duration-300 ${
          open ? "opacity-100 translate-y-0 pointer-events-auto" : "opacity-0 translate-y-4 pointer-events-none"
        }`}
        aria-hidden={!open}
      >
        {channels.map((ch) => (
          <a
            key={ch.id}
            href={ch.href}
            target={ch.id !== "chat" ? "_blank" : undefined}
            rel={ch.id !== "chat" ? "noopener noreferrer" : undefined}
            className="flex items-center gap-3 bg-white rounded-2xl shadow-lg border border-[#E2EDF4] px-4 py-2.5 hover:shadow-xl hover:-translate-x-0.5 transition-all duration-200 group"
            onClick={() => setOpen(false)}
          >
            <span className="text-sm font-semibold text-[#1A2332] group-hover:text-[#0077B6] transition-colors">
              {ch.label}
            </span>
            <span
              className="w-9 h-9 rounded-xl flex items-center justify-center text-white shrink-0"
              style={{ backgroundColor: ch.color }}
            >
              {ch.icon}
            </span>
          </a>
        ))}
      </div>

      {/* Main trigger button */}
      <button
        onClick={() => setOpen((v) => !v)}
        aria-label={open ? "Закрыть поддержку" : "Открыть поддержку"}
        className={`w-14 h-14 rounded-full shadow-xl flex items-center justify-center transition-all duration-300 focus:outline-none focus-visible:ring-2 focus-visible:ring-[#00B4D8] focus-visible:ring-offset-2 ${
          open
            ? "bg-[#1A2332] rotate-45"
            : "bg-gradient-to-br from-[#00B4D8] to-[#0077B6] hover:scale-110"
        }`}
      >
        {open ? (
          /* X icon */
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2.5" strokeLinecap="round">
            <line x1="18" y1="6" x2="6" y2="18" />
            <line x1="6" y1="6" x2="18" y2="18" />
          </svg>
        ) : (
          /* Headset icon */
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M3 18v-6a9 9 0 0 1 18 0v6" />
            <path d="M21 19a2 2 0 0 1-2 2h-1a2 2 0 0 1-2-2v-3a2 2 0 0 1 2-2h3z" />
            <path d="M3 19a2 2 0 0 0 2 2h1a2 2 0 0 0 2-2v-3a2 2 0 0 0-2-2H3z" />
          </svg>
        )}
      </button>

      {/* Pulse ring when closed */}
      {!open && (
        <span className="absolute bottom-0 right-0 w-14 h-14 rounded-full bg-[#00B4D8]/30 animate-ping pointer-events-none" />
      )}
    </div>
  );
}
